import androidx.annotation.MainThread

object DeepLinkHandler {
    const val SCHEME = "myapp"

    @MainThread
    fun handle(context: Context, uri: Uri?): Boolean {
        if (uri == null) return false
        if (!uri.isHierarchical) return false
        if (!uri.scheme.equals(SCHEME, ignoreCase = true)) return false

        val host = (uri.host ?: "").lowercase()
        val segments = uri.pathSegments ?: emptyList()

        val intent = when (host) {
            "profile" -> {
                val userId = segments.getOrNull(0)?.toLongOrNull() ?: return false
                ProfileActivity.newIntent(context, userId)
            }
            "payment" -> {
                val action = segments.getOrNull(0)?.lowercase()
                when (action) {
                    "confirm" -> PaymentConfirmActivity.newIntent(context)
                    else -> return false
                }
            }
            else -> return false
        }

        if (context !is Activity) {
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        }
        context.startActivity(intent)
        return true
    }
}

class DeepLinkActivity : Activity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        DeepLinkHandler.handle(this, intent?.data)
